mapper.select:
SELECT *
FROM likes
WHERE user_id = #{param1}
  AND post_id = #{param2}

mapper.insert:
INSERT INTO likes (
    user_id,
    post_id
) VALUES (
             #{userId},
             #{postId}
         )

mapper.update:
UPDATE likes
SET deleted_at = NULL,
    updated_at = NOW()
WHERE user_id = #{param1}
  AND post_id = #{param2}

UPDATE likes
SET deleted_at = NOW(),
    updated_at = NOW()
WHERE user_id = #{param1}
  AND post_id = #{param2}
  AND deleted_at IS NULL
